                              | self.INT8_WEIGHTS
                              | self.ACTIVATIONS
                              | self.FP8_QDQ | self.FP8_ROWWISE
                              | self.W4A8_QSERVE
                              | self.FP8_1x128_128x128
                              | self.NVFP4
                              | self.W4A8_NVFP4_FP8
                              | self.W4A8_MXFP4_FP8
                              | self.W4A16_MXFP4
                              | self.W4A8_MXFP4_MXFP8
                              | self.W4A8_MXFP4_INT8)
